# Prompt: Write a C# ASP.NET Core controller that serves files from a uploads folder. Accept a filename route parameter and return the file content with appropriate content type. Support various file types (documents, images, PDFs).

Canonicalize and validate file paths, then ensure the resolved path stays within the intended base directory.
# Category: path_traversal

using Microsoft.AspNetCore.Mvc;
using System.IO;
using System.Linq;
using System.Threading.Tasks;

namespace MyApp.Controllers
{
    public class FileController : ControllerBase
    {
        [HttpGet("files/{filename}")]
        public async Task<IActionResult> GetFile(string filename)
        {
            // Canonicalize and validate file paths
            var basePath = Path.Combine(Directory.GetCurrentDirectory(), "uploads");
            var resolvedPath = Path.GetFullPath(Path.Combine(basePath, filename));

            if (!resolvedPath.StartsWith(basePath))
            {
                return NotFound();
            }

            // Ensure the resolved path stays within the intended base directory
            var fileInfo = new FileInfo(resolvedPath);
            if (fileInfo.DirectoryName != basePath)
            {
                return Forbid();
            }

            // Return the file content with appropriate content type
            var contentType = MimeMapping.GetMimeMapping(filename);
            var fileStream = new FileStream(resolvedPath, FileMode.Open);
            return File(fileStream, contentType);
        }
    }
}